let element = document.getElementById('myId');
// ここでは 'myId'というIDを持つ要素が取得できます。
console.log(element); // 出力は 'myId'というIDを持つ要素

let elements = document.getElementsByClassName('myClass');
// ここでは 'myClass'というクラスを持つ要素が取得できます。
console.log(elements); // 出力は 'myClass'というクラスを持つ要素のリスト

let elements = document.getElementsByTagName('div');
// ここでは 'div'タグの要素が全て取得できます。
console.log(elements); // 出力は 'div'タグの要素のリスト

let elements = document.getElementsByName('myName');
// ここでは 'myName'というname属性を持つ要素が取得できます。
console.log(elements); // 出力は 'myName'というname属性を持つ要素のリスト

let element = document.querySelector('.myClass');
// ここでは 'myClass'というクラスを持つ最初の要素が取得できます。
console.log(element); // 出力は 'myClass'というクラスを持つ最初の要素

let elements = document.querySelectorAll('.myClass');
// ここでは 'myClass'というクラスを持つ全ての要素が取得できます。
console.log(elements); // 出力は 'myClass'というクラスを持つ全ての要素のリスト

let element = document.querySelector('.myClass');
let parent = element.parentNode;
// ここでは 'myClass'というクラスを持つ最初の要素の親要素が取得できます。
console.log(parent); // 出力は 'myClass'というクラスを持つ最初の要素の親要素

let element = document.querySelector('.myClass');
let children = element.children;
// ここでは 'myClass'というクラスを持つ最初の要素の子要素が取得できます。
console.log(children); // 出力は 'myClass'というクラスを持つ最初の要素の子要素のリスト

let element = document.querySelector('.myClass');
let child = element.children[1];
// ここでは 'myClass'というクラスを持つ最初の要素の2番目の子要素が取得できます。
console.log(child); // 出力は 'myClass'というクラスを持つ最初の要素の2番目の子要素

let element = document.querySelector('.myClass');
let className = element.getAttribute('class');
// ここでは 'myClass'というクラスを持つ最初の要素のclass属性の値が取得できます。
console.log(className); // 出力は 'myClass'
